#include <stdio.h>
#include <stdlib.h>
#include <cuda_runtime.h>
#include <sys/time.h>

long long get_time()
{
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

#define BLOCK_SIZE 16
#define BLOCK_SIZE_C BLOCK_SIZE
#define BLOCK_SIZE_R BLOCK_SIZE

#define STR_SIZE	256

#define MAX_PD	(3.0e6)

#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100

#define FACTOR_CHIP	0.5

typedef float FLOAT;

const FLOAT t_chip = 0.0005;
const FLOAT chip_height = 0.016;
const FLOAT chip_width = 0.016;

const FLOAT amb_temp = 80.0;

// CUDA kernel for single iteration
__global__ void single_iteration_kernel(FLOAT *result, FLOAT *temp, FLOAT *power, int row, int col,
                                        FLOAT Cap_1, FLOAT Rx_1, FLOAT Ry_1, FLOAT Rz_1)
{
    int r = blockIdx.y * BLOCK_SIZE_R + threadIdx.y;
    int c = blockIdx.x * BLOCK_SIZE_C + threadIdx.x;

    if (r >= row || c >= col) return;

    FLOAT delta;
    int idx = r * col + c;

    // Handle boundary conditions
    if (r == 0 && c == 0) {
        delta = (Cap_1) * (power[idx] +
            (temp[idx + 1] - temp[idx]) * Rx_1 +
            (temp[idx + col] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (r == 0 && c == col-1) {
        delta = (Cap_1) * (power[idx] +
            (temp[idx - 1] - temp[idx]) * Rx_1 +
            (temp[idx + col] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (r == row-1 && c == col-1) {
        delta = (Cap_1) * (power[idx] +
            (temp[idx - 1] - temp[idx]) * Rx_1 +
            (temp[idx - col] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (r == row-1 && c == 0) {
        delta = (Cap_1) * (power[idx] +
            (temp[idx + 1] - temp[idx]) * Rx_1 +
            (temp[idx - col] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (r == 0) {
        delta = (Cap_1) * (power[idx] +
            (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
            (temp[idx + col] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (c == col-1) {
        delta = (Cap_1) * (power[idx] +
            (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
            (temp[idx - 1] - temp[idx]) * Rx_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (r == row-1) {
        delta = (Cap_1) * (power[idx] +
            (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
            (temp[idx - col] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else if (c == 0) {
        delta = (Cap_1) * (power[idx] +
            (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
            (temp[idx + 1] - temp[idx]) * Rx_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }
    else {
        delta = (Cap_1) * (power[idx] +
            (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 +
            (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }

    result[idx] = temp[idx] + delta;
}

void compute_tran_temp(FLOAT *result, int num_iterations, FLOAT *temp, FLOAT *power, int row, int col) 
{
    FLOAT grid_height = chip_height / row;
    FLOAT grid_width = chip_width / col;

    FLOAT Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    FLOAT Rx = grid_width / (2.0 * K_SI * t_chip * grid_height);
    FLOAT Ry = grid_height / (2.0 * K_SI * t_chip * grid_width);
    FLOAT Rz = t_chip / (K_SI * grid_height * grid_width);

    FLOAT max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    FLOAT step = PRECISION / max_slope / 1000.0;

    FLOAT Rx_1 = 1.f / Rx;
    FLOAT Ry_1 = 1.f / Ry;
    FLOAT Rz_1 = 1.f / Rz;
    FLOAT Cap_1 = step / Cap;

    // Allocate CUDA memory
    FLOAT *d_result, *d_temp, *d_power;
    int array_size = row * col;
    cudaMalloc(&d_result, array_size * sizeof(FLOAT));
    cudaMalloc(&d_temp, array_size * sizeof(FLOAT));
    cudaMalloc(&d_power, array_size * sizeof(FLOAT));

    // Copy input data to GPU
    cudaMemcpy(d_temp, temp, array_size * sizeof(FLOAT), cudaMemcpyHostToDevice);
    cudaMemcpy(d_power, power, array_size * sizeof(FLOAT), cudaMemcpyHostToDevice);

    // Setup kernel dimensions
    dim3 block(BLOCK_SIZE_C, BLOCK_SIZE_R);
    dim3 grid((col + BLOCK_SIZE_C - 1) / BLOCK_SIZE_C, (row + BLOCK_SIZE_R - 1) / BLOCK_SIZE_R);

    FLOAT *d_r = d_result;
    FLOAT *d_t = d_temp;

    for (int i = 0; i < num_iterations; i++) {
        single_iteration_kernel<<<grid, block>>>(d_r, d_t, d_power, row, col, Cap_1, Rx_1, Ry_1, Rz_1);
        cudaDeviceSynchronize();

        // Swap pointers
        FLOAT *tmp = d_t;
        d_t = d_r;
        d_r = tmp;
    }

    // Copy result back to host (d_t holds the final result after swapping)
    cudaMemcpy(result, d_t, array_size * sizeof(FLOAT), cudaMemcpyDeviceToHost);

    // Free CUDA memory
    cudaFree(d_result);
    cudaFree(d_temp);
    cudaFree(d_power);
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
    exit(1);
}

void writeoutput(FLOAT *vect, int grid_rows, int grid_cols, char *file) {
    int i, j, index = 0;
    FILE *fp;
    char str[STR_SIZE];

    if ((fp = fopen(file, "w")) == 0)
        printf("The file was not opened\n");

    for (i = 0; i < grid_rows; i++)
        for (j = 0; j < grid_cols; j++) {
            sprintf(str, "%d\t%g\n", index, vect[i * grid_cols + j]);
            fputs(str, fp);
            index++;
        }

    fclose(fp);
}

void read_input(FLOAT *vect, int grid_rows, int grid_cols, char *file)
{
    int i, index;
    FILE *fp;
    char str[STR_SIZE];
    FLOAT val;

    fp = fopen(file, "r");
    if (!fp)
        fatal("file could not be opened for reading");

    for (i = 0; i < grid_rows * grid_cols; i++) {
        fgets(str, STR_SIZE, fp);
        if (feof(fp))
            fatal("not enough lines in file");
        if ((sscanf(str, "%f", &val) != 1))
            fatal("invalid file format");
        vect[i] = val;
    }

    fclose(fp);
}

void usage(int argc, char **argv)
{
    fprintf(stderr, "Usage: %s <grid_rows> <grid_cols> <sim_time> <no. of threads><temp_file> <power_file>\n", argv[0]);
    fprintf(stderr, "\t<grid_rows>  - number of rows in the grid (positive integer)\n");
    fprintf(stderr, "\t<grid_cols>  - number of columns in the grid (positive integer)\n");
    fprintf(stderr, "\t<sim_time>   - number of iterations\n");
    fprintf(stderr, "\t<no. of threads>   - number of threads\n");
    fprintf(stderr, "\t<temp_file>  - name of the file containing the initial temperature values of each cell\n");
    fprintf(stderr, "\t<power_file> - name of the file containing the dissipated power values of each cell\n");
    fprintf(stderr, "\t<output_file> - name of the output file\n");
    exit(1);
}

int main(int argc, char **argv)
{
    int grid_rows, grid_cols, sim_time, i;
    FLOAT *temp, *power, *result;
    char *tfile, *pfile, *ofile;

    if (argc != 8)
        usage(argc, argv);
    if ((grid_rows = atoi(argv[1])) <= 0 ||
        (grid_cols = atoi(argv[2])) <= 0 ||
        (sim_time = atoi(argv[3])) <= 0 ||
        (atoi(argv[4])) <= 0)
        usage(argc, argv);

    temp = (FLOAT *)calloc(grid_rows * grid_cols, sizeof(FLOAT));
    power = (FLOAT *)calloc(grid_rows * grid_cols, sizeof(FLOAT));
    result = (FLOAT *)calloc(grid_rows * grid_cols, sizeof(FLOAT));
    if (!temp || !power)
        fatal("unable to allocate memory");

    tfile = argv[5];
    pfile = argv[6];
    ofile = argv[7];

    read_input(temp, grid_rows, grid_cols, tfile);
    read_input(power, grid_rows, grid_cols, pfile);

    printf("Start computing the transient temperature\n");

    long long start_time = get_time();

    compute_tran_temp(result, sim_time, temp, power, grid_rows, grid_cols);

    long long end_time = get_time();

    printf("Ending simulation\n");
    printf("Total time: %.3f seconds\n", ((float)(end_time - start_time)) / (1000 * 1000));

    writeoutput((1 & sim_time) ? result : temp, grid_rows, grid_cols, ofile);

    free(temp);
    free(power);
    free(result);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <cuda_runtime.h>
#include <sys/time.h>

#define BLOCK_SIZE 16
#define BLOCK_SIZE_C BLOCK_SIZE
#define BLOCK_SIZE_R BLOCK_SIZE

#define STR_SIZE	256
#define MAX_PD	(3.0e6)
#define PRECISION	0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP	0.5

typedef float FLOAT;

const FLOAT t_chip = 0.0005;
const FLOAT chip_height = 0.016;
const FLOAT chip_width = 0.016;
const FLOAT amb_temp = 80.0;

long long get_time()
{
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
    exit(1);
}

__global__ void single_iteration_kernel(FLOAT *result, FLOAT *temp, FLOAT *power, int row, int col,
                                      FLOAT Cap_1, FLOAT Rx_1, FLOAT Ry_1, FLOAT Rz_1)
{
    int r = blockIdx.y * BLOCK_SIZE_R + threadIdx.y;
    int c = blockIdx.x * BLOCK_SIZE_C + threadIdx.x;

    if (r >= row || c >= col) return;

    FLOAT delta;
    int idx = r * col + c;

    if ((r == 0) && (c == 0)) {
        delta = Cap_1 * (power[idx] +
            (temp[idx + 1] - temp[idx]) * Rx_1 +
            (temp[idx + col] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }	
    else if ((r == 0) && (c == col-1)) {
        delta = Cap_1 * (power[idx] +
            (temp[idx - 1] - temp[idx]) * Rx_1 +
            (temp[idx + col] - temp[idx]) * Ry_1 +
            (amb_temp - temp[idx]) * Rz_1);
    }	
    else if ((r == row-1) && (c == col-1)) {
        delta = Cap_1 * (power[idx] + 
            (temp[idx - 1] - temp[idx]) * Rx_1 + 
            (temp[idx - col] - temp[idx]) * Ry_1 + 
            (amb_temp - temp[idx]) * Rz_1);					
    }	
    else if ((r == row-1) && (c == 0)) {
        delta = Cap_1 * (power[idx] + 
            (temp[idx + 1] - temp[idx]) * Rx_1 + 
            (temp[idx - col] - temp[idx]) * Ry_1 + 
            (amb_temp - temp[idx]) * Rz_1);
    }	
    else if (r == 0) {
        delta = Cap_1 * (power[idx] + 
            (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 + 
            (temp[idx + col] - temp[idx]) * Ry_1 + 
            (amb_temp - temp[idx]) * Rz_1);
    }	
    else if (c == col-1) {
        delta = Cap_1 * (power[idx] + 
            (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 + 
            (temp[idx - 1] - temp[idx]) * Rx_1 + 
            (amb_temp - temp[idx]) * Rz_1);
    }	
    else if (r == row-1) {
        delta = Cap_1 * (power[idx] + 
            (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 + 
            (temp[idx - col] - temp[idx]) * Ry_1 + 
            (amb_temp - temp[idx]) * Rz_1);
    }	
    else if (c == 0) {
        delta = Cap_1 * (power[idx] + 
            (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 + 
            (temp[idx + 1] - temp[idx]) * Rx_1 + 
            (amb_temp - temp[idx]) * Rz_1);
    }
    else {
        delta = Cap_1 * (power[idx] + 
            (temp[idx + col] + temp[idx - col] - 2.0f * temp[idx]) * Ry_1 + 
            (temp[idx + 1] + temp[idx - 1] - 2.0f * temp[idx]) * Rx_1 + 
            (amb_temp - temp[idx]) * Rz_1);
    }

    result[idx] = temp[idx] + delta;
}

void compute_tran_temp(FLOAT *result, int num_iterations, FLOAT *temp, FLOAT *power, int row, int col) 
{
    FLOAT grid_height = chip_height / row;
    FLOAT grid_width = chip_width / col;

    FLOAT Cap = FACTOR_CHIP * SPEC_HEAT_SI * t_chip * grid_width * grid_height;
    FLOAT Rx = grid_width / (2.0 * K_SI * t_chip * grid_height);
    FLOAT Ry = grid_height / (2.0 * K_SI * t_chip * grid_width);
    FLOAT Rz = t_chip / (K_SI * grid_height * grid_width);

    FLOAT max_slope = MAX_PD / (FACTOR_CHIP * t_chip * SPEC_HEAT_SI);
    FLOAT step = PRECISION / max_slope / 1000.0;

    FLOAT Rx_1 = 1.0f / Rx;
    FLOAT Ry_1 = 1.0f / Ry;
    FLOAT Rz_1 = 1.0f / Rz;
    FLOAT Cap_1 = step / Cap;

    #ifdef VERBOSE
    fprintf(stdout, "total iterations: %d s\tstep size: %g s\n", num_iterations, step);
    fprintf(stdout, "Rx: %g\tRy: %g\tRz: %g\tCap: %g\n", Rx, Ry, Rz, Cap);
    #endif

    int array_size = row * col;

    FLOAT *d_temp, *d_power, *d_result;
    cudaMalloc(&d_temp, array_size * sizeof(FLOAT));
    cudaMalloc(&d_power, array_size * sizeof(FLOAT));
    cudaMalloc(&d_result, array_size * sizeof(FLOAT));

    cudaMemcpy(d_temp, temp, array_size * sizeof(FLOAT), cudaMemcpyHostToDevice);
    cudaMemcpy(d_power, power, array_size * sizeof(FLOAT), cudaMemcpyHostToDevice);

    dim3 block(BLOCK_SIZE_C, BLOCK_SIZE_R);
    dim3 grid((col + BLOCK_SIZE_C - 1) / BLOCK_SIZE_C, (row + BLOCK_SIZE_R - 1) / BLOCK_SIZE_R);

    FLOAT* r = d_result;
    FLOAT* t = d_temp;
    for (int i = 0; i < num_iterations; i++)
    {
        #ifdef VERBOSE
        fprintf(stdout, "iteration %d\n", i);
        #endif
        single_iteration_kernel<<<grid, block>>>(r, t, d_power, row, col, Cap_1, Rx_1, Ry_1, Rz_1);
        cudaDeviceSynchronize();
        FLOAT* tmp = t;
        t = r;
        r = tmp;
    }	

    cudaMemcpy(result, t, array_size * sizeof(FLOAT), cudaMemcpyDeviceToHost);

    cudaFree(d_temp);
    cudaFree(d_power);
    cudaFree(d_result);

    #ifdef VERBOSE
    fprintf(stdout, "iteration %d\n", num_iterations);
    #endif
}

void writeoutput(FLOAT *vect, int grid_rows, int grid_cols, char *file) {

    int i, j, index = 0;
    FILE *fp;
    char str[STR_SIZE];

    if ((fp = fopen(file, "w")) == 0)
        printf("The file was not opened\n");

    for (i = 0; i < grid_rows; i++) 
        for (j = 0; j < grid_cols; j++)
        {
            sprintf(str, "%d\t%g\n", index, vect[i * grid_cols + j]);
            fputs(str, fp);
            index++;
        }

    fclose(fp);	
}

void read_input(FLOAT *vect, int grid_rows, int grid_cols, char *file)
{
    int i, index;
    FILE *fp;
    char str[STR_SIZE];
    FLOAT val;

    fp = fopen(file, "r");
    if (!fp)
        fatal("file could not be opened for reading");

    for (i = 0; i < grid_rows * grid_cols; i++) {
        fgets(str, STR_SIZE, fp);
        if (feof(fp))
            fatal("not enough lines in file");
        if (sscanf(str, "%f", &val) != 1)
            fatal("invalid file format");
        vect[i] = val;
    }

    fclose(fp);	
}

